/**
 * @summary List vaccination records
 */
export const getListVaccinationsUrl = (params?: ListVaccinationsParams) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) {
      normalizedParams.append(key, value === null ? "null" : value.toString());
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0
    ? `/api/vaccinations?${stringifiedParams}`
    : `/api/vaccinations`;
};

export const listVaccinations = async (
  params?: ListVaccinationsParams,
  options?: RequestInit,
): Promise<Vaccination[]> => {
  return customFetch<Vaccination[]>(getListVaccinationsUrl(params), {
    ...options,
    method: "GET",
  });
};

export const getListVaccinationsQueryKey = (
  params?: ListVaccinationsParams,
) => {
  return [`/api/vaccinations`, ...(params ? [params] : [])] as const;
};

